### Swift Computed Properties

Computed properties do not store a value directly. Instead, they provide a getter and optionally a setter to compute and set other values indirectly.

**Computed Property Syntax:**

```swift
struct TypeName {
    var storedProperty: Type

    var computedProperty: Type {
        get {
            // Return computed value
            return someValue
        }
        set(newValue) {
            // Set related properties
        }
    }
}
```

**Read-Only Computed Properties:**

```swift
struct Circle {
    var radius: Double

    // Read-only computed property
    var area: Double {
        return Double.pi * radius * radius
    }

    var circumference: Double {
        2 * Double.pi * radius
    }
}

let circle = Circle(radius: 5)
print(circle.area)            // ~78.54
print(circle.circumference)  // ~31.42
```

**Read-Write Computed Properties:**

```swift
struct Rectangle {
    var width: Double
    var height: Double

    // Computed property with getter and setter
    var area: Double {
        get {
            return width * height
        }
        set {
            // Set width proportionally when area changes
            width = sqrt(newValue * width / height)
            height = newValue / width
        }
    }
}

struct Temperature {
    var celsius: Double

    var fahrenheit: Double {
        get {
            return celsius * 9 / 5 + 32
        }
        set {
            celsius = (newValue - 32) * 5 / 9
        }
    }
}

var temp = Temperature(celsius: 25)
print(temp.fahrenheit)  // 77.0
temp.fahrenheit = 100
print(temp.celsius)     // ~37.78
```

> **Key Point:** Read-only computed properties can omit the `get` keyword entirely. The shorthand form `var prop: Type { return value }` is cleaner.

Computed properties are recalculated each time they are accessed. Use stored properties for caching expensive values.

codeExample:
import Foundation

struct Person {
    var firstName: String
    var lastName: String

    // Read-only computed property
    var fullName: String {
        "\(firstName) \(lastName)"
    }

    // Read-write computed property
    var initials: String {
        get {
            String(firstName.first!) + String(lastName.first!)
        }
        set {
            let parts = newValue.uppercased()
            if parts.count >= 2 {
                firstName = String(parts.first!)
                lastName = String(parts.dropFirst().first!)
            }
        }
    }
}

var person = Person(firstName: "John", lastName: "Doe")
print("Full name: \(person.fullName)")
print("Initials: \(person.initials)")

person.initials = "JD"
print("After set: \(person.fullName)")

// Shorthand for read-only
struct Speed {
    var kilometersPerHour: Double
    var milesPerHour: Double {
        kilometersPerHour * 0.621371
    }
}

let speed = Speed(kilometersPerHour: 100)
print("\(speed.kilometersPerHour) km/h = \(String(format: "%.1f", speed.milesPerHour)) mph")
